function generaDriveLinks() {
  var rootId = "1rrCwYsK27d-LqNwzWZ19mH_VhKT8-YBY";
  var map = {};
  var errori = [];

  function scanFolder(folderId, path) {
    try {
      var folder = DriveApp.getFolderById(folderId);
      Logger.log("Scansione: " + path + " (" + folderId + ")");

      var files = folder.getFiles();
      var count = 0;
      while (files.hasNext()) {
        var f = files.next();
        var name = f.getName().replace(/\.[^.]+$/, "");
        map[name] = f.getId();
        count++;
      }
      Logger.log("  → " + count + " file trovati");

      var subs = folder.getFolders();
      while (subs.hasNext()) {
        var sub = subs.next();
        scanFolder(sub.getId(), path + "/" + sub.getName());
      }
    } catch(e) {
      errori.push("ERRORE in " + path + ": " + e.message);
      Logger.log("ERRORE in " + path + ": " + e.message);
    }
  }

  scanFolder(rootId, "root");

  Logger.log("=== TOTALE FILE: " + Object.keys(map).length + " ===");
  if (errori.length > 0) {
    Logger.log("ERRORI: " + errori.join(", "));
  }

  // Crea il file JSON
  try {
    var json = JSON.stringify(map, null, 2);
    var blob = Utilities.newBlob(json, "application/json", "drive_links.json");
    var file = DriveApp.createFile(blob);
    Logger.log("File creato con ID: " + file.getId());
    Logger.log("URL: " + file.getUrl());
  } catch(e) {
    Logger.log("ERRORE creazione file: " + e.message);
  }
}
